    @field_validator("OAUTH2_PROVIDER_ALLOWED_REDIRECT_URI_SCHEMES", mode="before")
    @classmethod
    def _split_oauth_schemes(cls, value: Any) -> Any:
        """Split a comma-delimited env string for the one non-generated list field.

        Every other list field is covered by the generated
        `_aqueduct_decode_list_fields` validator; this field is not a
        module-level setting in the legacy source, so it has no generated
        counterpart and needs its own split.
        """
        if isinstance(value, str):
            return [item.strip() for item in value.split(",") if item.strip()]
        return value

    @model_validator(mode="after")
    def _resolve_redis_urls(self) -> "AqueductSettings":
        """The `_redis_url` fallback chain in mitxpro/settings.py.

        ``REDISCLOUD_URL`` wins when set; otherwise fall back to
        ``REDIS_URL``. Any of ``CELERY_BROKER_URL``, ``CELERY_RESULT_BACKEND``,
        ``CELERY_REDBEAT_REDIS_URL``, or ``WAGTAIL_CACHE_URL`` that were not
        explicitly set default to this resolved Redis URL.
        """
        redis_url = dv.first_url(self.REDISCLOUD_URL, self.REDIS_URL)
        if self.CELERY_BROKER_URL is None:
            self.CELERY_BROKER_URL = redis_url
        if self.CELERY_RESULT_BACKEND is None:
            self.CELERY_RESULT_BACKEND = redis_url
        if self.CELERY_REDBEAT_REDIS_URL is None:
            self.CELERY_REDBEAT_REDIS_URL = redis_url
        if self.WAGTAIL_CACHE_URL is None:
            self.WAGTAIL_CACHE_URL = redis_url
        return self

    @model_validator(mode="after")
    def _collect_features(self) -> "AqueductSettings":
        """FEATURE_* flags: the legacy env scan plus source-supplied extras.

        ``get_features()`` reproduces `mitol.common.envs.get_features` exactly,
        including raising ``ImproperlyConfigured`` on values that are not
        true/false (the previous hand-written scan silently dropped them).
        Flags supplied by a non-env source (e.g. Vault) arrive as model
        extras and are overlaid via ``derivations.feature_flags``.
        """
        features: dict[str, Any] = get_features()
        features.update(dv.feature_flags(self.model_extra or {}))
        self.FEATURES = features
        return self

    @model_validator(mode="after")
    def _validate_s3_config(self) -> "AqueductSettings":
        """Mirror the S3 cross-field validation in mitxpro/settings.py."""
        if self.MITXPRO_USE_S3 and (
            not self.AWS_ACCESS_KEY_ID
            or not self.AWS_SECRET_ACCESS_KEY
            or not self.AWS_STORAGE_BUCKET_NAME
        ):
            raise ImproperlyConfigured(
                "You have enabled S3 support, but are missing one of "
                "AWS_ACCESS_KEY_ID, AWS_SECRET_ACCESS_KEY, or "
                "AWS_STORAGE_BUCKET_NAME"
            )
        return self

