    @model_validator(mode="after")
    def _build_databases(self) -> "AqueductSettings":
        """DATABASES via derivations.database_config.

        Unlike the legacy module, ``database_config`` never applies
        ``sslmode`` to a SQLite URL (SQLite's driver rejects it).
        """
        config = dv.database_config(
            self.DATABASE_URL,
            conn_max_age=self.MITXPRO_DB_CONN_MAX_AGE,
            ssl_require=not self.MITXPRO_DB_DISABLE_SSL,
        )
        config["DISABLE_SERVER_SIDE_CURSORS"] = self.MITXPRO_DB_DISABLE_SS_CURSORS
        config.setdefault("OPTIONS", {})
        self.DEFAULT_DATABASE_CONFIG = config
        self.DATABASES = {"default": config}
        return self

